return items.map(item => {
  const j = item.json;

  if (j.error) {
    // Handle 429/error items gracefully
    return {
      json: {
        ...j,
        verdict: null,
        reason: 'API rate limited - retry later',
        rawModelOutput: null
      }
    };
  }

  const raw = j.choices[0].message.content;  // Correct path
  let parsed;

  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    return {
      json: {
        ...j,
        verdict: null,
        reason: `Parse error: ${e.message}`,
        rawModelOutput: raw
      }
    };
  }

  return {
    json: {
      ...j,
      verdict: parsed.verdict,
      reason: parsed.reason,
      rawModelOutput: raw  // Keep for debugging
    }
  };
});

